  const {
    layout,
    toolbar,
    results,
    dialog
  } = useInbox({
    pageId,
    query
  });
  const items = results?.items?.map(item => ({
    ...item,
    groupId: 'search'
  }));
  const [bookmark, setBookmark] = useState(false);
  const Controls = () => <Button size="xs" variant="ghost" onClick={() => setBookmark(!bookmark)}>
      {bookmark ? <BookmarkFillIcon /> : <BookmarkIcon />}
      <span>{bookmark ? 'Lagret' : 'Lagre'}</span>
    </Button>;
  return <Layout {...layout} useGlobalHeader={true}>
      {dialog ? <Dialog {...dialog} activityLog={{
      onClick: () => alert('Aktivitetslogg'),
      label: 'Aktivitetslogg'
    }} /> : <PageBase>
          {toolbar && <Toolbar {...toolbar}>
              <Controls />
            </Toolbar>}
          {children || results && <DialogList title={title} description={description as DialogListProps['description']} items={items as DialogListProps['items']} groups={results?.groups} />}
        </PageBase>}
    </Layout>;
